// src/components/Sidebar.jsx
import React from 'react';
import {
  Home, CalendarDays, BookOpen, Users, UserRound, Mail, Settings,
  HelpCircle, Box, PackagePlus, PieChart, LayoutList,
} from "lucide-react";
import { useAuth } from "../context/AuthContext";

export default function Sidebar({ active, onMenuClick }) {
  const { user } = useAuth();
  const role = user?.role;

  return (
    <aside
      className={`
        bg-white shadow-xl rounded-2xl z-30 print:hidden
        flex flex-col justify-between
        w-full md:w-64
        h-auto md:h-[calc(100vh-32px)]
        fixed md:static top-16 md:top-4 left-0 md:ml-4
        mx-auto md:mx-0
        transition-all
        px-0 md:px-0
        md:rounded-2xl
      `}
      style={{
        maxWidth: "100vw",
      }}
    >
      {/* Topo: menu principal */}
      <nav className="flex flex-row md:flex-col gap-1 md:gap-2 px-2 md:px-4 py-2 md:py-0 overflow-x-auto">
        <MenuItem icon={<Home size={24} />} label="Dashboard" active={active === "dashboard"} onClick={() => onMenuClick("dashboard")} />
        <MenuItem icon={<CalendarDays size={24} />} label="Agendar Paciente" active={active === "agendar"} onClick={() => onMenuClick("agendar")} />
        <MenuItem icon={<Users size={24} />} label="Pacientes" active={active === "pacientes"} onClick={() => onMenuClick("pacientes")} />
        {/* hide for aluno */}
        {role !== "aluno" && (
          <>
            <MenuItem icon={<UserRound size={24} />} label="Alunos" active={active === "alunos"} onClick={() => onMenuClick("alunos")} />
            <MenuItem icon={<BookOpen size={24} />} label="Disciplinas" active={active === "disciplinas"} onClick={() => onMenuClick("disciplinas")} />
            <MenuItem icon={<Mail size={24} />} label="Períodos" active={active === "periodos"} onClick={() => onMenuClick("periodos")} />
            <hr className="my-2 border-t border-gray-200 hidden md:block" />
            <MenuItem icon={<PieChart size={24} />} label="Painel Esterilização" active={active === "dashboard-esterilizacao"} onClick={() => onMenuClick("dashboard-esterilizacao")} />
            <MenuItem icon={<Box size={24} />} label="Caixas" active={active === "caixas"} onClick={() => onMenuClick("caixas")} />
            <MenuItem icon={<PackagePlus size={24} />} label="Esterilização" active={active === "esterilizacao"} onClick={() => onMenuClick("esterilizacao")} />
          </>
        )}
      </nav>
      {/* Base: Configurações e Ajuda */}
      <div className="flex flex-row md:flex-col gap-1 md:gap-2 mb-2 md:mb-10 px-2 md:px-4">
        {role !== "aluno" && (
          <MenuItem icon={<LayoutList size={24} />} label="Auditoria" active={active === "auditoria"} onClick={() => onMenuClick("auditoria")} />
        )}
        <MenuItem icon={<HelpCircle size={24} />} label="Ajuda" active={active === "ajuda"} onClick={() => onMenuClick("ajuda")} />
      </div>
      {/* Extra - sombra e espaçamento mobile */}
      <style>{`
        @media (max-width: 767px) {
          aside {
            position: static !important;
            top: unset !important;
            left: 0 !important;
            height: auto !important;
            width: 100% !important;
            margin-left: 0 !important;
            margin-right: 0 !important;
            border-radius: 1.5rem !important;
            box-shadow: 0 2px 18px 0 rgba(100,116,139,0.09);
          }
        }
      `}</style>
    </aside>
  );
}

function MenuItem({ icon, label, active, onClick }) {
  return (
    <button
      onClick={onClick}
      className={`
        flex items-center gap-2 md:gap-3
        w-full whitespace-nowrap
        py-3 px-4 rounded-full text-base transition-all
        ${active ? "bg-[#D3E4FE] text-[#23263A]" : "text-[#23263A] hover:bg-gray-100"}
      `}
      style={{
        boxShadow: active
          ? "0px 2px 8px rgba(100, 116, 139, 0.08)"
          : undefined,
      }}
    >
      {icon}
      <span className="hidden sm:inline">{label}</span>
    </button>
  );
}
